### 7. HTTP Request/Response Middleware

**File**: `/Users/marcus/conductor/workspaces/brain/riga/app/src/server/http/request-logging.ts`

```typescript
export function withRequestLogging(route: string, method: string, handler: RouteHandler): RouteHandler {
  return async (request: RouteRequest) => {
    const startedAt = performance.now();
    const requestId = request.headers.get("x-request-id") ?? randomUUID();
    return runWithRequestContext(
      { requestId, method, route, path },
      async () => {
        try {
          const response = await handler(request);
          return withRequestIdHeader(response, requestId);
        } catch (error) {
          logError("http.request.failed", "HTTP request failed", error, ...);
          return jsonError("internal server error", 500);
        }
      },
    );
  };
}
```

**Adds to every request**:
- Unique `x-request-id` header (UUID if not provided by client)
- Structured logging with timestamps
- Top-level error boundary

