**`linkAuthUserToPerson` function** (in same file or separate `auth/hooks.ts`):

```typescript
async function linkAuthUserToPerson(
  surreal: Surreal,
  user: { id: string; name: string; email: string; image?: string },
): Promise<void> {
  const personId = randomUUID();
  const personRecord = new RecordId("person", personId);
  const userRecord = new RecordId("user", user.id);
  const workspaceRecord = new RecordId("workspace", "default");
  const now = new Date();

  // Create person node
  await surreal.create(personRecord).content({
    name: user.name,
    contact_email: user.email,
    identities: [{ provider: "github", id: user.id }],
    created_at: now,
    updated_at: now,
  });

  // Link auth user -> person via auth_identity relation
  await surreal
    .relate(userRecord, new RecordId("auth_identity", randomUUID()), personRecord, {
      linked_at: now,
    })
    .output("after");

  // Link person -> default workspace via member_of
  await surreal
    .relate(personRecord, new RecordId("member_of", randomUUID()), workspaceRecord, {
      role: "member",
      added_at: now,
    })
    .output("after");
}
```

