```typescript
import { createAdapterFactory } from "better-auth/adapters";
import { RecordId, type Surreal } from "surrealdb";

export function surrealdbAdapter(surreal: Surreal) {
  return createAdapterFactory({
    config: {
      adapterId: "surrealdb-v2",
      adapterName: "SurrealDB v2",
      usePlural: false,
      supportsJSON: true,
      supportsDates: true,
      supportsBooleans: true,
      supportsNumericIds: false,
      supportsJoin: false,
    },
    adapter: ({ schema }) => {
      // Build FK field map from schema metadata
      const fkFieldsMap = buildFkFieldsMap(schema);

      return {
        create: async ({ model, data }) => { ... },
        findOne: async ({ model, where }) => { ... },
        findMany: async ({ model, where, limit, offset, sortBy }) => { ... },
        update: async ({ model, where, update }) => { ... },
        updateMany: async ({ model, where, update }) => { ... },
        delete: async ({ model, where }) => { ... },
        deleteMany: async ({ model, where }) => { ... },
        count: async ({ model, where }) => { ... },
      };
    },
  });
}
```

**Key internal functions:**

1. **`buildFkFieldsMap(schema)`** -- Scans schema metadata to build a `Map<string, Map<string, string>>` mapping `model -> fieldName -> referencedTable`. For example, `session.userId -> "user"`. The `id` field is always a self-reference to the model table.

2. **`toRecordId(model, field, value, fkFields)`** -- Converts a string value to `RecordId` when the field is a known FK. Returns the value unchanged for non-FK fields.
   ```typescript
   function toRecordId(
     model: string,
     field: string,
     value: unknown,
     fkFields: Map<string, string>,
   ): unknown {
     if (typeof value !== "string") return value;
     if (field === "id") return new RecordId(model, value);
     const refTable = fkFields.get(field);
     if (refTable) return new RecordId(refTable, value);
     return value;
   }
   ```

3. **`transformInput(data, model, fkFields)`** -- Transforms all FK fields in a data object for write operations. Strips the `id` field from the content (since CREATE uses RecordId separately).

4. **`transformOutput(record, model)`** -- Converts RecordId fields back to plain strings for better-auth. Uses `instanceof RecordId` check and extracts `.id`.
   ```typescript
   function transformOutput(record: Record<string, unknown>): Record<string, unknown> {
     const output: Record<string, unknown> = {};
     for (const [key, value] of Object.entries(record)) {
       if (value instanceof RecordId) {
         output[key] = value.id as string;
       } else {
         output[key] = value;
       }
     }
     return output;
   }
   ```

5. **`buildWhereParams(where, model, fkFields)`** -- Builds a parameterized WHERE clause and params object. Returns `{ clause: string, params: Record<string, unknown> }`.
   ```typescript
   // Input: [{ field: "email", value: "a@b.com", operator: "eq" }, { field: "userId", value: "abc", operator: "eq" }]
   // Output: { clause: "email = $w0 AND userId = $w1", params: { w0: "a@b.com", w1: RecordId("user", "abc") } }
   ```
   Operator mapping:
   - `eq` -> `=`
   - `ne` -> `!=`
   - `gt` -> `>`
   - `lt` -> `<`
   - `in` -> `IN`
   - `contains` -> `CONTAINS`
   - `starts_with` -> `string::starts_with(field, $param)`
   - `ends_with` -> `string::ends_with(field, $param)`

**Method implementations (pseudocode):**

```typescript
create: async ({ model, data }) => {
  const fkFields = fkFieldsMap.get(model) ?? new Map();
  const id = data.id as string;
  const record = new RecordId(model, id);
  const content = transformInput(data, model, fkFields); // strips id, converts FKs

  const [result] = await surreal
    .query<[Record<string, unknown>[]]>(
      "CREATE $record CONTENT $content RETURN AFTER;",
      { record, content },
    )
    .collect<[Record<string, unknown>[]]>();

  if (!result[0]) throw new Error(`Failed to create ${model}`);
  return transformOutput(result[0]);
},

findOne: async ({ model, where }) => {
  const fkFields = fkFieldsMap.get(model) ?? new Map();
  const { clause, params } = buildWhereParams(where, model, fkFields);

  const [results] = await surreal
    .query<[Record<string, unknown>[]]>(
      `SELECT * FROM ${model} WHERE ${clause} LIMIT 1;`,
      params,
    )
    .collect<[Record<string, unknown>[]]>();

  const record = results[0];
  if (!record) return undefined; // project convention: no null
  return transformOutput(record);
},

findMany: async ({ model, where, limit, offset, sortBy }) => {
  const fkFields = fkFieldsMap.get(model) ?? new Map();
  let query = `SELECT * FROM ${model}`;
  let params: Record<string, unknown> = {};

  if (where && where.length > 0) {
    const w = buildWhereParams(where, model, fkFields);
    query += ` WHERE ${w.clause}`;
    params = w.params;
  }
  if (sortBy) {
    query += ` ORDER BY ${sortBy.field} ${sortBy.direction.toUpperCase()}`;
  }
  if (limit !== undefined) {
    query += ` LIMIT ${Number(limit)}`;
  }
  if (offset !== undefined) {
    query += ` START ${Number(offset)}`;
  }

  const [results] = await surreal
    .query<[Record<string, unknown>[]]>(query + ";", params)
    .collect<[Record<string, unknown>[]]>();

  return (results ?? []).map(transformOutput);
},

update: async ({ model, where, update: updateData }) => {
  const fkFields = fkFieldsMap.get(model) ?? new Map();
  const { clause, params } = buildWhereParams(where, model, fkFields);
  const content = transformInput(updateData, model, fkFields);

  const [results] = await surreal
    .query<[Record<string, unknown>[]]>(
      `UPDATE ${model} MERGE $data WHERE ${clause};`,
      { ...params, data: content },
    )
    .collect<[Record<string, unknown>[]]>();

  if (!results[0]) throw new Error(`Failed to update ${model}`);
  return transformOutput(results[0]);
},

delete: async ({ model, where }) => {
  const fkFields = fkFieldsMap.get(model) ?? new Map();
  const { clause, params } = buildWhereParams(where, model, fkFields);
  await surreal.query(`DELETE FROM ${model} WHERE ${clause};`, params);
},

count: async ({ model, where }) => {
  const fkFields = fkFieldsMap.get(model) ?? new Map();
  let query: string;
  let params: Record<string, unknown> = {};

  if (where && where.length > 0) {
    const w = buildWhereParams(where, model, fkFields);
    query = `SELECT count() FROM ${model} WHERE ${w.clause} GROUP ALL;`;
    params = w.params;
  } else {
    query = `SELECT count() FROM ${model} GROUP ALL;`;
  }

  const [results] = await surreal
    .query<[Array<{ count: number }>]>(query, params)
    .collect<[Array<{ count: number }>]>();

  return results[0]?.count ?? 0;
},
```

**Important note on `null` vs `undefined`:** better-auth's `findOne` is typed to return `null` when no record is found. The `createAdapterFactory` wrapper handles the conversion from the adapter's return value. The adapter can safely return `undefined` (matching project convention) and the factory will translate it to `null` for better-auth's internal consumption. However, if the factory does NOT handle this, we may need to return `null` specifically in `findOne` as an exception to the project's no-null rule, since this is at the library boundary.

---

### Phase 3: Auth Configuration

**File: `app/src/server/auth/config.ts`**

```typescript
import { betterAuth } from "better-auth";
import { randomUUID } from "node:crypto";
import { RecordId, type Surreal } from "surrealdb";
import { surrealdbAdapter } from "./adapter";

export type AuthConfig = {
  secret: string;
  baseURL: string;
  githubClientId: string;
  githubClientSecret: string;
};

export function createAuthInstance(surreal: Surreal, config: AuthConfig) {
  return betterAuth({
    secret: config.secret,
    baseURL: config.baseURL,
    basePath: "/api/auth",
    database: surrealdbAdapter(surreal),
    socialProviders: {
      github: {
        clientId: config.githubClientId,
        clientSecret: config.githubClientSecret,
      },
    },
    databaseHooks: {
      user: {
        create: {
          after: async (user) => {
            // Create domain person + link to default workspace
            await linkAuthUserToPerson(surreal, user);
          },
        },
      },
    },
  });
}
```

**`linkAuthUserToPerson` function** (in same file or separate `auth/hooks.ts`):

```typescript
async function linkAuthUserToPerson(
  surreal: Surreal,
  user: { id: string; name: string; email: string; image?: string },
): Promise<void> {
  const personId = randomUUID();
  const personRecord = new RecordId("person", personId);
  const userRecord = new RecordId("user", user.id);
  const workspaceRecord = new RecordId("workspace", "default");
  const now = new Date();

  // Create person node
  await surreal.create(personRecord).content({
    name: user.name,
    contact_email: user.email,
    identities: [{ provider: "github", id: user.id }],
    created_at: now,
    updated_at: now,
  });

  // Link auth user -> person via auth_identity relation
  await surreal
    .relate(userRecord, new RecordId("auth_identity", randomUUID()), personRecord, {
      linked_at: now,
    })
    .output("after");

  // Link person -> default workspace via member_of
  await surreal
    .relate(personRecord, new RecordId("member_of", randomUUID()), workspaceRecord, {
      role: "member",
      added_at: now,
    })
    .output("after");
}
```

